+          mode: 'production',
+          loader: { options },
+        });
+        const stats = await compile(compiler);
+        const codeFromBundle = getCodeFromBundle(stats, compiler);
+        const codeFromSass = getCodeFromSass(testId, {
+          ...options,
+          sassOptions: {
+            outputStyle: 'compressed',
+          },
+        });
+
+        expect(codeFromBundle.css).toBe(codeFromSass.css);
